            // 
            this.c_drop_status_name.DataMember = "Query";
            this.c_drop_status_name.Expression = "\'สถานะการเปลี่ยนแปลง  :  \' + [DROP_STATUS_NAME]";
            this.c_drop_status_name.Name = "c_drop_status_name";
            // 
            // c_dec
            // 
            this.c_dec.DataMember = "Query";
            this.c_dec.Expression = "Iif(   [PERIOD_PAYMENT_OLD] >  [PERIOD_PAYMENT_NEW]  and   [PERIOD_PAYMENT_NEW]  " +
    "<> 0 ,1,0)";
            this.c_dec.Name = "c_dec";
            // 
            // c_drop
            // 
            this.c_drop.DataMember = "Query";
            this.c_drop.Expression = "Iif(   [period_payment_old] =  [period_payment_new] ,1,0)";
            this.c_drop.Name = "c_drop";
            // 
            // c_inc
            // 
            this.c_inc.DataMember = "Query";
            this.c_inc.Expression = "Iif(   [period_payment_old] <  [period_payment_new] ,1,0)";
            this.c_inc.Name = "c_inc";
            // 
            // c_dec_amt
            // 
            this.c_dec_amt.DataMember = "Query";
            this.c_dec_amt.Expression = "Iif(   [period_payment_old] >  [period_payment_new] and   [period_payment_new] <>" +
    " 0 ,  [period_payment_old] -  [period_payment_new] , 0)";
            this.c_dec_amt.Name = "c_dec_amt";
            // 
            // c_drop_amt
            // 
            this.c_drop_amt.DataMember = "Query";
            this.c_drop_amt.Expression = "Iif(   [period_payment_old] =  [period_payment_new] ,  [period_payment_old] ,0)";
            this.c_drop_amt.Name = "c_drop_amt";
            // 
            // c_inc_amt
            // 
            this.c_inc_amt.DataMember = "Query";
            this.c_inc_amt.Expression = "Iif(   [period_payment_old] <  [period_payment_new] ,  [period_payment_new] -  [p" +
    "eriod_payment_old] , 0)";
            this.c_inc_amt.Name = "c_inc_amt";
            // 
            // c_net
            // 
            this.c_net.DataMember = "Query";
            this.c_net.Expression = " sum(  [c_inc_amt] ) - sum(  [c_drop_amt] ) - sum(  [c_dec_amt] )";
            this.c_net.Name = "c_net";
            // 
            // c_net_0
            // 
            this.c_net_0.DataMember = "Query";
            this.c_net_0.Expression = " Iif( [c_net] > 0 ,\'สัญญาเพิ่มขึ้น\', \'สัญญาลดลง\')";
            this.c_net_0.Name = "c_net_0";
            // 
            // c_sum_net
            // 
            this.c_sum_net.DataMember = "Query";
            this.c_sum_net.Expression = "Iif( [c_net] > 0 , [c_net] , -[c_net] )";
            this.c_sum_net.Name = "c_sum_net";
